/**
 * Provider-specific content block mappers for OTel gen_ai attributes.
 *
 * Each function maps a single provider SDK content block to its
 * OTel-compliant part object, as defined in the gen_ai semantic conventions.
 *
 * These are passed as the `contentBlockMapper` parameter to
 * `formatInputMessages` and `formatOutputMessage`.
 */

// =============================================================================
// Anthropic
// =============================================================================
//  Maps a single Anthropic SDK content block to its OTel-compliant part object.
//
//   text                      → TextPart
//   image (base64)            → BlobPart       { modality: "image", mime_type from block }
//   image (url)               → UriPart        { modality: "image" }
//   document (base64)         → BlobPart       { mime_type from block — may be "application/pdf" or "text/plain" }
//   document (text)           → TextPart
//   document (url)            → UriPart        { mime_type: "application/pdf" }
//   document (file)           → FilePart       { file_id from source.file_id }
//   tool_use                  → ToolCallRequestPart
//   tool_result               → ToolCallResponsePart  (response may be string or content block array)
//   server_tool_use           → ServerToolCallPart
//   thinking                  → ReasoningPart  (OTel type is "reasoning", not "thinking")
//   redacted_thinking         → GenericPart    { type: "redacted_thinking" }  — data intentionally omitted
//   <unknown>                 → GenericPart

/**
 * Maps a single Anthropic content block to its OTel-compliant part object.
 * Used by formatInputMessages, formatOutputMessage, and formatSystemInstructions.
 */
export function mapAnthropicContentBlock(block: any): object {
  if (typeof block === "string") {
    return { type: "text", content: block };
  }

  switch (block.type) {
    // -------------------------------------------------------------------------
    // Text
    // -------------------------------------------------------------------------
    case "text":
      return { type: "text", content: block.text };

    // -------------------------------------------------------------------------
    // Image — sources: base64 | url
    // -------------------------------------------------------------------------
    case "image": {
      const src = block.source;
      if (src?.type === "base64") {
        return {
          type: "blob",
          modality: "image",
          mime_type: src.media_type, // e.g. "image/jpeg", "image/png", "image/webp", "image/gif"
          content: src.data,
        };
      }
      if (src?.type === "url") {
        return { type: "uri", modality: "image", uri: src.url };
      }
      // Unknown image source shape — fall through to GenericPart
      return { type: block.type, ...block };
    }

    // -------------------------------------------------------------------------
    // Document — sources: base64 | text | url | file
    // OTel modality accepts any string (anyOf: [Modality enum, string]), so
    // "document" is a valid value for BlobPart/UriPart/FilePart modality.
    // -------------------------------------------------------------------------
    case "document": {
      const src = block.source;
      switch (src?.type) {
        case "base64":
          // Inline base64 — media_type comes from the block itself, never hardcode it
          // (can be "application/pdf" or "text/plain")
          return {
            type: "blob",
            modality: "document",
            mime_type: src.media_type,
            content: src.data,
          };
        case "text":
          // Inline plain text document
          return { type: "text", content: src.data };
        case "url":
          // URL-referenced PDF
          return {
            type: "uri",
            modality: "document",
            mime_type: "application/pdf",
            uri: src.url,
          };
        case "file":
          // Files API reference — file_id is on source.file_id
          return { type: "file", modality: "document", file_id: src.file_id };
        default:
          return { type: block.type, ...block };
      }
    }

    // -------------------------------------------------------------------------
    // Tool use (client-side function call requested by the model)
    // -------------------------------------------------------------------------
    case "tool_use":
      return {
        type: "tool_call",
        id: block.id,
        name: block.name,
        arguments: block.input,
      };

    // -------------------------------------------------------------------------
    // Tool result (client sends function result back to the model)
    // Note: block.content may be a string OR an array of content blocks
    // -------------------------------------------------------------------------
    case "tool_result":
      return {
        type: "tool_call_response",
        id: block.tool_use_id,
        response: block.content,
      };

    // -------------------------------------------------------------------------
    // Server-side tool use (e.g. web_search, code_execution — run by Anthropic)
    // -------------------------------------------------------------------------
    case "server_tool_use":
      return {
        type: "server_tool_call",
        id: block.id,
        name: block.name,
        server_tool_call: { type: block.name, ...block.input },
      };

    // -------------------------------------------------------------------------
    // Extended thinking / reasoning
    // -------------------------------------------------------------------------
    case "thinking":
      // OTel ReasoningPart uses type "reasoning", not "thinking"
      return { type: "reasoning", content: block.thinking };

    case "redacted_thinking":
      // Anthropic redacts thinking blocks when they contain sensitive content.
      // The `data` field is an opaque encrypted blob — intentionally not logged.
      return { type: "redacted_thinking" };

    // -------------------------------------------------------------------------
    // Unknown / future block types — preserve as GenericPart
    // -------------------------------------------------------------------------
    default:
      return { type: block.type, ...block };
  }
}

// =============================================================================
// OpenAI
// =============================================================================
//  Maps a single OpenAI SDK input content part to its OTel-compliant part object.
//
//  This mapper handles the REQUEST-side content parts that appear in user messages
//  (ChatCompletionContentPart union). OpenAI's response is flat (not block-based),
//  so output mapping is handled by buildOpenAIOutputMessage in message-helpers.ts.
//
//   text                      → TextPart
//   image_url (regular URL)   → UriPart        { modality: "image" }
//   image_url (data: URI)     → BlobPart       { modality: "image", mime_type parsed from URI }
//   input_audio               → BlobPart       { modality: "audio", mime_type: "audio/{format}" }
//   file (file_id)            → FilePart       { modality: "document", file_id }
//   file (file_data)          → BlobPart       { modality: "document", mime_type }
//   refusal                   → GenericPart    { type: "refusal", content }
//   <unknown>                 → GenericPart

/**
 * Maps a single OpenAI SDK content part to its OTel-compliant part object.
 * Used for input content parts in user messages.
 */
export function mapOpenAIContentBlock(block: any): object {
  if (typeof block === "string") {
    return { type: "text", content: block };
  }

  switch (block.type) {
    // -------------------------------------------------------------------------
    // Text
    // -------------------------------------------------------------------------
    case "text":
      return { type: "text", content: block.text };

    // -------------------------------------------------------------------------
    // Image URL — can be a regular URL or a base64 data: URI
    // -------------------------------------------------------------------------
    case "image_url": {
      const url = block.image_url?.url;
      if (url && url.startsWith("data:")) {
        // Parse data URI: data:image/png;base64,xxxx
        const match = url.match(/^data:([^;]+);base64,(.+)$/);
        if (match) {
          return {
            type: "blob",
            modality: "image",
            mime_type: match[1],
            content: match[2],
          };
        }
      }
      return { type: "uri", modality: "image", uri: url };
    }

    // -------------------------------------------------------------------------
    // Input audio — base64 encoded audio data with format
    // -------------------------------------------------------------------------
    case "input_audio":
      return {
        type: "blob",
        modality: "audio",
        mime_type: `audio/${block.input_audio?.format || "wav"}`,
        content: block.input_audio?.data,
      };

    // -------------------------------------------------------------------------
    // File — can be file_id reference or inline file_data
    // OpenAI file content parts are used for documents (PDFs etc.), not images
    // (images use image_url). modality accepts any string, so "document" is valid.
    // -------------------------------------------------------------------------
    case "file": {
      if (block.file?.file_id) {
        return {
          type: "file",
          modality: "document",
          file_id: block.file.file_id,
          ...(block.file.filename && { filename: block.file.filename }),
        };
      }
      if (block.file?.file_data) {
        // Inline file data → BlobPart. OTel FilePart is a reference type (file_id only).
        return {
          type: "blob",
          modality: "document",
          mime_type: block.file.mime_type || "application/octet-stream",
          content: block.file.file_data,
        };
      }
      return { type: block.type, ...block };
    }

    // -------------------------------------------------------------------------
    // Refusal — assistant content part indicating safety refusal
    // -------------------------------------------------------------------------
    case "refusal":
      return { type: "refusal", content: block.refusal };

    // -------------------------------------------------------------------------
    // Unknown / future content part types — preserve as GenericPart
    // -------------------------------------------------------------------------
    default:
      return { type: block.type, ...block };
  }
}

// =============================================================================
// Bedrock
// =============================================================================
//  Maps a single Bedrock SDK content block to its OTel-compliant part object.
//
//  Bedrock is used by multiple providers (Anthropic, AI21, Amazon Nova, Meta,
//  Cohere) — all share the same block schema on the Bedrock layer:
//
//   plain string              → TextPart
//   { type: "text", text }    → TextPart
//   { text } (Nova format)    → TextPart
//   tool_use                  → ToolCallRequestPart
//   tool_result               → ToolCallResponsePart
//   <unknown>                 → GenericPart

/** Bedrock SDK content block type strings. */
const BedrockBlockType = {
  TEXT: "text",
  TOOL_USE: "tool_use",
  TOOL_RESULT: "tool_result",
} as const;

/** OTel gen_ai part type strings used by the Bedrock mapper. */
const BedrockOtelPartType = {
  TEXT: "text",
  TOOL_CALL: "tool_call",
  TOOL_CALL_RESPONSE: "tool_call_response",
} as const;

/**
 * Maps a single Bedrock content block to its OTel-compliant part object.
 * Used by formatInputMessages and formatOutputMessage for all Bedrock providers.
 */
export const mapBedrockContentBlock = (block: any): object => {
  if (typeof block === "string") {
    return { type: BedrockOtelPartType.TEXT, content: block };
  }

  switch (block.type) {
    case BedrockBlockType.TEXT:
      return { type: BedrockOtelPartType.TEXT, content: block.text };

    case BedrockBlockType.TOOL_USE:
      return {
        type: BedrockOtelPartType.TOOL_CALL,
        id: block.id,
        name: block.name,
        arguments: block.input,
      };

    case BedrockBlockType.TOOL_RESULT:
      return {
        type: BedrockOtelPartType.TOOL_CALL_RESPONSE,
        id: block.tool_use_id,
        response: block.content,
      };

    default:
      if (!block.type && block.text !== undefined) {
        return { type: BedrockOtelPartType.TEXT, content: block.text };
      }
      return { type: block.type, ...block };
  }
};

// =============================================================================
// Vercel AI SDK
// =============================================================================
//  Maps a single Vercel AI SDK content part (from ai.prompt.messages span attr)
//  to its OTel-compliant part object. Verified against:
//    - AI SDK v6 ToolCallPart / ToolResultPart / ImagePart / FilePart / ReasoningPart types
//    - OTel gen_ai input/output messages JSON schemas (v1.40)
//
//   text       → TextPart               { type:"text", content }
//   reasoning  → ReasoningPart          { type:"reasoning", content }
//   tool-call  → ToolCallRequestPart    { type:"tool_call", id?, name, arguments? }
//   tool-result→ ToolCallResponsePart   { type:"tool_call_response", id?, response }
//   image (string data URI) → BlobPart  { modality:"image", mime_type?, content }
//   image (string URL)      → UriPart   { modality:"image", uri }
//   image (URL object)      → UriPart   { modality:"image", uri: url.href }
//   image (binary data)     → BlobPart  { modality:"image", content (base64) }
//   file (inline data)      → BlobPart  { modality inferred from mediaType, content }
//   file (URL)              → UriPart   { modality inferred from mediaType, uri }
//   <unknown>               → GenericPart

/**
 * Content part type values as emitted by the Vercel AI SDK v6 in span attributes.
 * Source: @ai-sdk/provider-utils ToolCallPart / ToolResultPart / ImagePart / FilePart / ReasoningPart
 */
const enum AiSdkPartType {
  Text = "text",
  Reasoning = "reasoning",
  ToolCall = "tool-call",
  ToolResult = "tool-result",
  Image = "image",
  File = "file",
}

/**
 * Maps a single Vercel AI SDK content part to its OTel-compliant part object.
 *
 * Field names follow AI SDK v6:
 *   ToolCallPart:   toolCallId, toolName, input
 *   ToolResultPart: toolCallId, toolName, output (ToolResultOutput union)
 *   ImagePart:      image (DataContent | URL), optional mediaType
 *   FilePart:       data (DataContent | URL), mediaType (required)
 *   ReasoningPart:  text
 */
export const mapAiSdkContentPart = (part: any): any => {
  if (!part || typeof part !== "object") {
    return { type: AiSdkPartType.Text, content: String(part ?? "") };
  }

  switch (part.type) {
    case AiSdkPartType.Text:
      return { type: AiSdkPartType.Text, content: part.text ?? "" };

    // OTel type is "reasoning", AI SDK v6 field is `text`
    case AiSdkPartType.Reasoning:
      return { type: AiSdkPartType.Reasoning, content: part.text ?? "" };

    case AiSdkPartType.ToolCall:
      // AI SDK v6: toolCallId, toolName, input
      return {
        type: "tool_call",
        id: part.toolCallId ?? null,
        name: part.toolName,
        arguments: part.input,
      };

    case AiSdkPartType.ToolResult: {
      // AI SDK v6: output is ToolResultOutput — { type: 'text'|'json', value } union
      // Unwrap to the actual value for tracing; fall back to the full object if unknown shape
      const output = part.output;
      const response =
        output && typeof output === "object" && "value" in output
          ? output.value
          : output;
      return {
        type: "tool_call_response",
        id: part.toolCallId ?? null,
        response,
      };
    }

    case AiSdkPartType.Image: {
      // AI SDK v6: image is DataContent | URL; optional mediaType
      const imgSrc = part.image ?? null;
      const mimeType = part.mediaType ?? null;

      if (imgSrc instanceof URL) {
        return {
          type: "uri",
          modality: "image",
          uri: imgSrc.href,
          mime_type: mimeType,
        };
      }
      if (typeof imgSrc === "string") {
        if (imgSrc.startsWith("data:")) {
          const [header, data] = imgSrc.split(",");
          const detectedMime = header.match(/data:([^;]+)/)?.[1] ?? mimeType;
          return {
            type: "blob",
            modality: "image",
            ...(detectedMime ? { mime_type: detectedMime } : {}),
            content: data || "",
          };
        }
        return {
          type: "uri",
          modality: "image",
          uri: imgSrc,
          mime_type: mimeType,
        };
      }
      if (imgSrc != null) {
        // Binary data (Uint8Array / ArrayBuffer / Buffer) — base64 encode
        const bytes =
          imgSrc instanceof ArrayBuffer ? new Uint8Array(imgSrc) : imgSrc;
        const b64 = Buffer.from(bytes).toString("base64");
        return {
          type: "blob",
          modality: "image",
          mime_type: mimeType,
          content: b64,
        };
      }
      return { type: "blob", modality: "image", content: "" };
    }

    case AiSdkPartType.File: {
      // AI SDK v6: data is DataContent | URL; mediaType is required
      const fileSrc = part.data ?? null;
      const mimeType = part.mediaType ?? null;
      // Infer modality from MIME type (best-effort)
      const modality = mimeType?.startsWith("image/")
        ? "image"
        : mimeType?.startsWith("audio/")
          ? "audio"
          : mimeType?.startsWith("video/")
            ? "video"
            : "document";

      if (fileSrc instanceof URL) {
        return {
          type: "uri",
          modality,
          uri: fileSrc.href,
          mime_type: mimeType,
        };
      }
      if (typeof fileSrc === "string") {
        if (fileSrc.startsWith("data:")) {
          const [, data] = fileSrc.split(",");
          return {
            type: "blob",
            modality,
            mime_type: mimeType,
            content: data || "",
          };
        }
        return { type: "uri", modality, uri: fileSrc, mime_type: mimeType };
      }
      if (fileSrc != null) {
        const bytes =
          fileSrc instanceof ArrayBuffer ? new Uint8Array(fileSrc) : fileSrc;
        const b64 = Buffer.from(bytes).toString("base64");
        return { type: "blob", modality, mime_type: mimeType, content: b64 };
      }
      return { type: "blob", modality, content: "" };
    }

    default:
      // GenericPart — preserve unknown types as-is
      return { type: part.type, ...part };
  }
};

/**
 * Converts Vercel AI SDK message content to an array of OTel parts.
 * Accepts: plain string, array of SDK content parts, or a JSON-serialized array
 * (the AI SDK serializes content arrays as JSON strings in span attributes).
 */
export const mapAiSdkMessageContent = (content: any): any[] => {
  if (typeof content === "string") {
    try {
      const parsed = JSON.parse(content);
      if (Array.isArray(parsed)) {
        return parsed.map(mapAiSdkContentPart);
      }
    } catch {
      // plain string
    }
    return [{ type: "text", content }];
  }

  if (Array.isArray(content)) {
    return content.map(mapAiSdkContentPart);
  }

  if (content && typeof content === "object") {
    return [mapAiSdkContentPart(content)];
  }

  return [{ type: "text", content: String(content ?? "") }];
};
